vibra = context:getSystemService(Context.VIBRATOR_SERVICE)local android = import('android.*')import "android.graphics.Color"import "android.content.res.ColorStateList"import "android.animation.LayoutTransition"import "androidx.appcompat.widget.LinearLayoutCompat"local material3 = require 'material3'local context = material3:getContext()local MDC_R = luajava.bindClass ("com.google.android.material.R")local LinearLayoutCompat = bindClass("androidx.appcompat.widget.LinearLayoutCompat")import 'com.google.android.material.dialog.MaterialAlertDialogBuilder'import 'com.google.android.material.slider.Slider'import 'com.google.android.material.snackbar.Snackbar'import "com.google.android.material.navigationrail.NavigationRailView"import "com.google.android.material.card.MaterialCardView"context:setTheme(R.style.AppTheme)context = app.contextwindow = context:getSystemService("window") -- 获取窗口管理器function getLayoutParams()	LayoutParams = WindowManager.LayoutParams	layoutParams = luajava.new(LayoutParams)	if (Build.VERSION.SDK_INT >= 26) then -- 设置悬浮窗方式		layoutParams.type = LayoutParams.TYPE_APPLICATION_OVERLAY		else		layoutParams.type = LayoutParams.TYPE_PHONE	end	layoutParams.format = PixelFormat.RGBA_8888 -- 设置背景	layoutParams.flags = LayoutParams.FLAG_NOT_FOCUSABLE -- 焦点设置Finish	layoutParams.gravity = Gravity.TOP|Gravity.LEFT -- 重力设置	layoutParams.width = LayoutParams.WRAP_CONTENT -- 布局宽度	layoutParams.height = LayoutParams.WRAP_CONTENT -- 布局高度	return layoutParamsendfunction getCorner(gtvb1,gtvb3,gtvb4,gtvb5,g1,g2,g3,g4)if not gtvb4 then gtvb4 = 0 gtvb5 = 0xff000000 endlocal jianbians = luajava.new(GradientDrawable)jianbians:setCornerRadius(gtvb3)jianbians:setGradientType(GradientDrawable.LINEAR_GRADIENT)jianbians:setColors(gtvb1)jianbians:setStroke(gtvb4,gtvb5)--边框宽度和颜色jianbians:setCornerRadii({g1,g1,g2,g2,g3,g3,g4,g4})return jianbiansendfunction getVerticalBG(gtvb1,gtvb3,gtvb4,gtvb5)  if not gtvb4 then gtvb4=0 gtvb5=0xff161616